function StaggerCard({ children, index, style }) {
  const [ref, vis] = useReveal();
  return (
    <div ref={ref} style={{ ...style, opacity: vis ? 1 : 0, transform: vis ? "translateY(0)" : "translateY(36px)",
      transition: `opacity 0.7s ease-out ${index * 150}ms, transform 0.7s ease-out ${index * 150}ms` }}>
      {children}
    </div>
  );
}

function CalendarButton() {
  const googleUrl = "https://calendar.google.com/calendar/render?action=TEMPLATE&text=Daniel+%26+Edelys+Wedding&dates=20260731T140000Z/20260731T220000Z&details=Ceremony+at+Sarasota+County+Courthouse%2C+followed+by+Reception+at+Terra+Gaucha+Brazilian+Steakhouse%2C+Tampa.&location=2000+Main+Street%2C+Sarasota%2C+FL";
  const downloadIcs = () => {
    const lines = [
      "BEGIN:VCALENDAR","VERSION:2.0","PRODID:-//Daniel & Edelys Wedding//EN",
      "CALSCALE:GREGORIAN","METHOD:PUBLISH","BEGIN:VEVENT",
      "DTSTART:20260731T140000","DTEND:20260731T220000",
      "SUMMARY:Daniel & Edelys Wedding",
      "LOCATION:2000 Main Street\, Sarasota\, FL",
      "DESCRIPTION:Ceremony at Sarasota County Courthouse. Reception at Terra Gaucha Brazilian Steakhouse\, Tampa.",
      "END:VEVENT","END:VCALENDAR"
    ].join("\r\n");
    const isSafari = /^((?!chrome|android).)*safari/i.test(navigator.userAgent) || /iPad|iPhone|iPod/.test(navigator.userAgent);
    if (isSafari) {
      window.open("data:text/calendar;charset=utf-8," + encodeURIComponent(lines));
    } else {
      const blob = new Blob([lines], { type:"text/calendar;charset=utf-8" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url; a.download = "daniel-edelys-wedding.ics";
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
      setTimeout(() => URL.revokeObjectURL(url), 1000);
    }
  };
  const btnStyle = { fontFamily:"'Lora', serif", fontSize:10, letterSpacing:3, fontWeight:600, textTransform:"uppercase",
    padding:"11px 24px", borderRadius:2, cursor:"pointer", border:`1px solid ${P.sageFa}`, background:"transparent", color:P.inkF };
  return (
    <div style={{ display:"flex", gap:12, flexWrap:"wrap", justifyContent:"center", marginTop:32 }}>
      <a href={googleUrl} target="_blank" rel="noopener noreferrer" style={{ textDecoration:"none" }}>
        <button style={btnStyle}>+ Google Calendar</button>
      </a>
      <button style={btnStyle} onClick={downloadIcs}>+ Apple / iCal</button>
    </div>
  );
}

function Confetti() {
  const colors = [P.burg, P.burgFa, P.sage, P.sageFa, "#F5EDE4", P.burgLt, "#A8BF9A"];
  const pieces = Array.from({ length: 70 }, (_, i) => ({
    left: `${(i * 13.7) % 100}%`,
    delay: `${(i * 0.06) % 1}s`,
    dur: `${1.4 + (i * 0.07) % 1}s`,
    color: colors[i % colors.length],
    w: 5 + (i * 3) % 7,
    h: 3 + (i * 2) % 5,
    rot: (i * 47) % 360,
  }));
  return (
    <div style={{ position:"fixed", inset:0, pointerEvents:"none", zIndex:9998, overflow:"hidden" }}>
      {pieces.map((p, i) => (
        <div key={i} style={{ position:"absolute", left:p.left, top:"-12px", width:p.w, height:p.h,
          background:p.color, borderRadius:1, opacity:0.9,
          animation:`confettiFall ${p.dur} ${p.delay} ease-in forwards`,
          transform:`rotate(${p.rot}deg)` }} />
      ))}
    </div>
  );
}

function CustomCursor() {
  const [pos, setPos] = useState({ x:-100, y:-100 });
  const [hovered, setHovered] = useState(false);
  useEffect(() => {
    const move = (e) => setPos({ x: e.clientX, y: e.clientY });
    const over = (e) => setHovered(!!(e.target.closest("button,a,[role='button']")));
    document.addEventListener("mousemove", move);
    document.addEventListener("mouseover", over);
    return () => { document.removeEventListener("mousemove", move); document.removeEventListener("mouseover", over); };
  }, []);
  return (
    <div style={{ position:"fixed", left:pos.x, top:pos.y, transform:"translate(-50%,-50%)",
      pointerEvents:"none", zIndex:99998, transition:"width 0.15s, height 0.15s",
      width: hovered ? 36 : 20, height: hovered ? 36 : 20 }}>
      <svg width="100%" height="100%" viewBox="0 0 36 36">
        <circle cx="18" cy="18" r="16" fill="none" stroke={P.burg} strokeWidth="1" opacity={hovered ? 0.7 : 0.45} />
        {!hovered && <circle cx="18" cy="18" r="2" fill={P.burg} opacity="0.5" />}
      </svg>
    </div>
  );
}

function Sec({ id, children, bg }) {
  const [ref, vis] = useReveal();
  return (
    <section ref={ref} id={id} style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
      padding: "100px 28px", background: bg || P.bg, position: "relative", overflow: "hidden",
      opacity: vis ? 1 : 0, transform: vis ? "translateY(0)" : "translateY(48px)",
      transition: "opacity 0.9s ease-out, transform 0.9s ease-out" }}>
      {children}
    </section>
  );
}

